(window.webpackJsonp=window.webpackJsonp||[]).push([[192],{702:function(v,_,t){"use strict";t.r(_);var p=t(3),n=Object(p.a)({},(function(){var v=this,_=v.$createElement,t=v._self._c||_;return t("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[t("p",[t("strong",[v._v("深圳新闻网")]),v._v("北京3月3日讯（特派记者 王海婷）虽然被媒体亲切称为“小马哥”，马化腾却经常“冷对”媒体，但当他作为新任全国人大代表出现在两会广东团住地，仍然引起不懈围堵。3月3日，深圳新闻网记者专访到这位难访的“小马哥”，他不仅与记者分享了对中国互联网产业现状和未来发展的看法，腾讯未来发展战略，以及作为全国人大代表的履职计划，还首度回应了“腾讯抄袭”的质疑。")]),v._v(" "),t("p",[t("strong",[v._v("谈所提建议：应从国家战略层面推进互联网行业发展")])]),v._v(" "),t("p",[v._v("“过去中国互联网发展是野生的，没有指导就生出来，政府强调管理，没有太多考虑发展得好不好。” 马化腾表示，此次作为广东仅有的2位来自互联网行业的全国人大代表之一，他建议政府能从顶层设计上支持、从国家战略上推动互联网行业发展。")]),v._v(" "),t("p",[v._v("如何从战略上推动？马化腾举例说，中国无线宽带现在完全依靠运营商，成本很高，网速慢、资费却很高。“这是如高速公路一样是基本设施，应更多由国家承担，找国企承建，设很多关卡，向用户收费，这很阻碍发展。”他以深圳市政府推动“无线城市”项目举例，希望国家在战略层面能够有所动作，支持互联网行业发展。")]),v._v(" "),t("p",[v._v("此外，马化腾认为，在互联网立法方面中国仍处于“事件推动”阶段，“出了个大事才想怎么办，这样非常被动”，希望国家能够尽快主动推进互联网立法。")]),v._v(" "),t("p",[v._v("谈公司战略：微信将会“走出去” 考虑申请金融牌照在接受采访过程中，有记者友善表示，许多两会上的记者团队作战时都会用微信交流，小马哥开心大笑表示感谢。他透露，腾讯正在计划推动让微信“走出去”。 “中国较大的国际化企业华为、中兴都在深圳，但他们都是制造业，我希望微信成为中国的国际化互联网平台。” 据悉，微信的国际化战略首先在香港、台湾试点，接下来将推印尼、越南等东南亚地区，目前在美国也已经设了办公室。")]),v._v(" "),t("p",[v._v("马化腾还表示会考虑申请金融牌照。目前腾讯已经有了支付牌照，通过和平安合作参与了保险。在与马云、马明哲合作设立的新保险公司中，三方会贡献自己所拥有的资源。")]),v._v(" "),t("p",[t("strong",[v._v("谈“抄袭”质疑：你做了车别人就不能制造车了吗？")])]),v._v(" "),t("p",[v._v("对于记者提出的“有人说腾讯做的产品在抄袭”的质疑，马化腾表示，腾讯只是从事了别人做过的行业，并没有人能举出证据证明腾讯抄袭，如果存在抄袭腾讯早已被告倒。")]),v._v(" "),t("p",[v._v("“你做了车别人就不能制造车了吗？很多东西其他互联网公司都在做，因为我们第一个做得那么全面，所以压力全部压我们身上，随着时间推演，加上我们创新投入，新产品推出，这种质疑越来越少。”")]),v._v(" "),t("p",[v._v("谈两会履职：将吸取教训认真参会 努力为互联网行业发声")]),v._v(" "),t("p",[v._v("在深圳两会时，马化腾曾因迟到20分钟参会被媒体曝光，再被问到这事件，马化腾幽默表示，“上次迟到20分钟就被你们写了，这次我会汲取教训，全程参加。”")]),v._v(" "),t("p",[v._v("对于自己未来5年的全国人大代表生涯，马化腾承诺将认真履职。")]),v._v(" "),t("p",[v._v("“之前全国人大没有一位互联网行业代表，前5年全国两会也没有互联网的声音，今年广东省就有2位，因为这个产业已经这么大了，希望能够借此机会加大力度为互联网行业发声。”")]),v._v(" "),t("p",[v._v("马化腾认为，代表履职最重要的是提出一些可实施，有前瞻性的问题，如果大家都扑在热点上会很重复，行业代表要提自己行业有关的建议，但不能只从公司角度，而是应该从国家发展角度提出建议。")])])}),[],!1,null,null,null);_.default=n.exports}}]);